import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { filterEvents } from '../../api/api';
import toast from 'react-hot-toast';

const TYPES    = ['ALL','MOVIE','CONCERT','EVENT'];
const GENRES   = ['ALL','Action','Drama','Comedy','Romance','Horror','Thriller','Pop','Rock','Classical','Festival','Sports','Cultural','Music','Other'];
const LANGS    = ['ALL','English','Tamil','Hindi','Telugu','Malayalam','Kannada'];
const STATUSES = ['ALL','ACTIVE','COMPLETED','CANCELLED'];

const TYPE_ICON  = { MOVIE: '🎬', CONCERT: '🎵', EVENT: '🎪' };
const TYPE_COLOR = { MOVIE: '#2563a8', CONCERT: '#c97d1a', EVENT: '#1a8f63' };
const TYPE_BG    = { MOVIE: 'linear-gradient(135deg,#0f2a5e,#1a3a7a)', CONCERT: 'linear-gradient(135deg,#3d2000,#7a4500)', EVENT: 'linear-gradient(135deg,#0a2e1a,#14522f)' };

const SORT_OPTIONS = [
  { value: '',           label: 'Default'    },
  { value: 'name-asc',   label: 'A → Z'      },
  { value: 'name-desc',  label: 'Z → A'      },
  { value: 'type',       label: 'Type'       },
  { value: 'genre',      label: 'Genre'      },
  { value: 'duration',   label: 'Duration'   },
];

const clientSort = (events, sortBy) => {
  if (!sortBy) return events;
  const arr = [...events];
  switch (sortBy) {
    case 'name-asc':  return arr.sort((a,b) => a.name.localeCompare(b.name));
    case 'name-desc': return arr.sort((a,b) => b.name.localeCompare(a.name));
    case 'type':      return arr.sort((a,b) => (a.type||'').localeCompare(b.type||''));
    case 'genre':     return arr.sort((a,b) => (a.genre||'').localeCompare(b.genre||''));
    case 'duration':  return arr.sort((a,b) => (a.duration||'').localeCompare(b.duration||''));
    default:          return arr;
  }
};

const BrowsePage = () => {
  const navigate = useNavigate();
  const [allEvents, setAllEvents] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [filters, setFilters]     = useState({ type: '', genre: '', language: '', status: '' });
  const [sortBy, setSortBy]       = useState('');
  const [search, setSearch]       = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const params = {};
      if (filters.type)     params.type     = filters.type;
      if (filters.genre)    params.genre    = filters.genre;
      if (filters.language) params.language = filters.language;
      if (filters.status)   params.status   = filters.status;
      if (search.trim())    params.name     = search.trim();
      const res  = await filterEvents(params);
      setAllEvents(Array.isArray(res.data?.data) ? res.data.data : []);
    } catch {
      toast.error('Failed to load events');
      setAllEvents([]);
    } finally { setLoading(false); }
  }, [filters, search]);

  useEffect(() => { load(); }, [load]);

  const events = clientSort(allEvents, sortBy);
  const setFilter = (key, val) => setFilters((f) => ({ ...f, [key]: val === 'ALL' ? '' : val }));
  const activeFilterCount = Object.values(filters).filter(Boolean).length;

  // Featured = first ACTIVE event
  const featured = events.find((e) => e.status === 'ACTIVE');
  const rest = featured ? events.filter((e) => e.eventId !== featured.eventId) : events;

  return (
    <div style={{ background: '#0c0e13', minHeight: '100vh', fontFamily: '"DM Sans", system-ui, sans-serif', color: '#e8e4de' }}>

      {/* ── Cinematic Hero Search ── */}
      <div style={{
        position: 'relative', overflow: 'hidden',
        padding: '64px 40px 48px',
        background: 'linear-gradient(180deg, #12151e 0%, #0c0e13 100%)',
        borderBottom: '1px solid rgba(255,255,255,0.06)',
      }}>
        {/* Background pattern */}
        <div style={{
          position: 'absolute', inset: 0, opacity: 0.04,
          backgroundImage: 'radial-gradient(circle at 25% 25%, #e05c2a 0%, transparent 50%), radial-gradient(circle at 75% 75%, #2563a8 0%, transparent 50%)',
          pointerEvents: 'none',
        }} />

        <div style={{ maxWidth: '1200px', margin: '0 auto', position: 'relative' }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: '8px',
            background: 'rgba(224,92,42,0.12)', border: '1px solid rgba(224,92,42,0.3)',
            borderRadius: '99px', padding: '4px 14px', marginBottom: '20px',
          }}>
            <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#e05c2a', display: 'inline-block', animation: 'blink 1.5s infinite' }} />
            <span style={{ fontSize: '11px', fontWeight: 700, color: '#e05c2a', letterSpacing: '0.1em' }}>LIVE EVENTS</span>
          </div>

          <h1 style={{
            fontFamily: '"Playfair Display", Georgia, serif',
            fontSize: 'clamp(2.8rem, 6vw, 5rem)',
            fontWeight: 900, lineHeight: 0.95,
            color: '#f5f0e8', marginBottom: '20px',
            letterSpacing: '-0.02em',
          }}>
            Discover<br />
            <span style={{ color: '#e05c2a', fontStyle: 'italic' }}>Events</span>
          </h1>

          <p style={{ fontSize: '16px', color: '#6b7280', marginBottom: '32px', maxWidth: '420px', lineHeight: 1.6 }}>
            Movies, concerts & live events — find your next unforgettable experience.
          </p>

          {/* Search */}
          <div style={{ position: 'relative', maxWidth: '560px' }}>
            <span style={{ position: 'absolute', left: '18px', top: '50%', transform: 'translateY(-50%)', fontSize: '18px', pointerEvents: 'none' }}>🔍</span>
            <input
              placeholder="Search movies, concerts, events..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{
                width: '100%', padding: '16px 20px 16px 52px',
                background: 'rgba(255,255,255,0.07)',
                border: '1px solid rgba(255,255,255,0.12)',
                borderRadius: '14px',
                color: '#f5f0e8', fontSize: '15px',
                outline: 'none',
                backdropFilter: 'blur(20px)',
                fontFamily: '"DM Sans", system-ui, sans-serif',
                boxSizing: 'border-box',
                transition: 'border-color 0.2s',
              }}
              onFocus={(e) => e.target.style.borderColor = 'rgba(224,92,42,0.5)'}
              onBlur={(e) => e.target.style.borderColor = 'rgba(255,255,255,0.12)'}
            />
          </div>

          {/* Type pills */}
          <div style={{ display: 'flex', gap: '10px', marginTop: '24px', flexWrap: 'wrap' }}>
            {TYPES.map((t) => {
              const active = filters.type === (t === 'ALL' ? '' : t);
              const color = TYPE_COLOR[t] || '#6b7280';
              return (
                <button key={t} onClick={() => setFilter('type', t)} style={{
                  padding: '8px 20px', borderRadius: '99px',
                  border: `1px solid ${active ? color : 'rgba(255,255,255,0.12)'}`,
                  background: active ? `${color}25` : 'rgba(255,255,255,0.05)',
                  color: active ? color : '#9ca3af',
                  fontSize: '13px', fontWeight: 700, cursor: 'pointer',
                  display: 'flex', alignItems: 'center', gap: '6px',
                  fontFamily: '"DM Sans", system-ui, sans-serif',
                  transition: 'all 0.15s',
                }}>
                  {TYPE_ICON[t] || '✦'} {t}
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* ── Main content ── */}
      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '32px 40px 60px', display: 'flex', gap: '32px' }}>

        {/* ── Sidebar ── */}
        <div style={{ width: '200px', flexShrink: 0 }}>
          <div style={{ position: 'sticky', top: '24px' }}>
            {activeFilterCount > 0 && (
              <button onClick={() => setFilters({ type:'', genre:'', language:'', status:'' })} style={{
                width: '100%', marginBottom: '20px', padding: '10px',
                borderRadius: '10px', border: '1px solid rgba(224,92,42,0.4)',
                background: 'rgba(224,92,42,0.1)', color: '#e05c2a',
                cursor: 'pointer', fontSize: '12px', fontWeight: 700,
                fontFamily: '"DM Sans", system-ui, sans-serif',
              }}>
                ✕ Clear {activeFilterCount} filter{activeFilterCount > 1 ? 's' : ''}
              </button>
            )}

            {[
              { title: 'GENRE',    items: GENRES,   key: 'genre'    },
              { title: 'LANGUAGE', items: LANGS,    key: 'language' },
              { title: 'STATUS',   items: STATUSES, key: 'status'   },
            ].map(({ title, items, key }) => (
              <div key={title} style={{ marginBottom: '28px' }}>
                <div style={{ fontSize: '10px', fontWeight: 700, letterSpacing: '0.15em', color: '#4b5563', marginBottom: '10px', textTransform: 'uppercase' }}>
                  {title}
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
                  {items.map((item) => {
                    const active = filters[key] === (item === 'ALL' ? '' : item);
                    return (
                      <button key={item} onClick={() => setFilter(key, item)} style={{
                        padding: '7px 12px', borderRadius: '8px', border: 'none',
                        cursor: 'pointer', textAlign: 'left', fontSize: '13px',
                        fontWeight: active ? 700 : 400,
                        background: active ? 'rgba(224,92,42,0.15)' : 'transparent',
                        color: active ? '#e05c2a' : '#6b7280',
                        fontFamily: '"DM Sans", system-ui, sans-serif',
                        transition: 'all 0.12s',
                      }}
                        onMouseEnter={(e) => { if (!active) e.currentTarget.style.color = '#e8e4de'; }}
                        onMouseLeave={(e) => { if (!active) e.currentTarget.style.color = '#6b7280'; }}
                      >{item}</button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* ── Results ── */}
        <div style={{ flex: 1, minWidth: 0 }}>

          {/* Toolbar */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', flexWrap: 'wrap', gap: '12px' }}>
            <div style={{ fontSize: '14px', color: '#6b7280' }}>
              {loading ? 'Searching...' : (
                <span><strong style={{ color: '#e8e4de' }}>{events.length}</strong> result{events.length !== 1 ? 's' : ''} found</span>
              )}
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <span style={{ fontSize: '11px', color: '#4b5563', fontWeight: 700, letterSpacing: '0.1em', textTransform: 'uppercase' }}>Sort</span>
              <select value={sortBy} onChange={(e) => setSortBy(e.target.value)} style={{
                padding: '8px 14px', borderRadius: '8px',
                background: 'rgba(255,255,255,0.07)',
                border: '1px solid rgba(255,255,255,0.12)',
                color: '#e8e4de', fontSize: '13px', cursor: 'pointer',
                fontFamily: '"DM Sans", system-ui, sans-serif',
                outline: 'none',
              }}>
                {SORT_OPTIONS.map((o) => <option key={o.value} value={o.value} style={{ background: '#1c1f2a' }}>{o.label}</option>)}
              </select>
            </div>
          </div>

          {loading ? (
            <div style={{ padding: '80px', textAlign: 'center', color: '#4b5563' }}>
              <div style={{ fontSize: '32px', marginBottom: '12px', animation: 'spin 1s linear infinite', display: 'inline-block' }}>⟳</div>
              <div>Loading events...</div>
            </div>
          ) : events.length === 0 ? (
            <div style={{ padding: '80px', textAlign: 'center', color: '#4b5563' }}>
              <div style={{ fontSize: '48px', marginBottom: '16px' }}>🎭</div>
              <div style={{ fontSize: '18px', color: '#6b7280', marginBottom: '8px' }}>No events found</div>
              <div style={{ fontSize: '14px' }}>Try adjusting your filters</div>
            </div>
          ) : (
            <div>
              {/* ── Featured card (large) ── */}
              {featured && (
                <div onClick={() => navigate(`/events/${featured.eventId}`)}
                  style={{
                    borderRadius: '20px', overflow: 'hidden', cursor: 'pointer',
                    marginBottom: '24px', position: 'relative',
                    background: TYPE_BG[featured.type] || 'linear-gradient(135deg,#1a1d2e,#252836)',
                    border: '1px solid rgba(255,255,255,0.08)',
                    minHeight: '220px',
                    display: 'flex', alignItems: 'flex-end',
                    transition: 'transform 0.2s, box-shadow 0.2s',
                  }}
                  onMouseEnter={(e) => { e.currentTarget.style.transform = 'translateY(-3px)'; e.currentTarget.style.boxShadow = '0 20px 60px rgba(0,0,0,0.4)'; }}
                  onMouseLeave={(e) => { e.currentTarget.style.transform = 'none'; e.currentTarget.style.boxShadow = 'none'; }}
                >
                  {/* Decorative circles */}
                  <div style={{ position: 'absolute', top: '-40px', right: '-40px', width: '240px', height: '240px', borderRadius: '50%', background: `${TYPE_COLOR[featured.type] || '#e05c2a'}15`, pointerEvents: 'none' }} />
                  <div style={{ position: 'absolute', top: '20px', right: '60px', fontSize: '80px', opacity: 0.15, pointerEvents: 'none' }}>
                    {TYPE_ICON[featured.type] || '🎪'}
                  </div>

                  {/* Featured badge */}
                  <div style={{
                    position: 'absolute', top: '20px', left: '24px',
                    background: '#e05c2a', color: 'white',
                    fontSize: '10px', fontWeight: 800, letterSpacing: '0.15em',
                    padding: '4px 12px', borderRadius: '99px',
                  }}>FEATURED</div>

                  <div style={{ padding: '32px', position: 'relative', zIndex: 1, flex: 1 }}>
                    <div style={{ display: 'flex', gap: '8px', marginBottom: '12px', flexWrap: 'wrap' }}>
                      <span style={{ fontSize: '11px', fontWeight: 700, color: TYPE_COLOR[featured.type] || '#e05c2a', background: `${TYPE_COLOR[featured.type] || '#e05c2a'}20`, padding: '3px 10px', borderRadius: '99px' }}>
                        {TYPE_ICON[featured.type]} {featured.type}
                      </span>
                      {featured.genre && featured.genre.split(',').slice(0,2).map((g) => (
                        <span key={g} style={{ fontSize: '11px', color: '#6b7280', background: 'rgba(255,255,255,0.08)', padding: '3px 10px', borderRadius: '99px' }}>{g.trim()}</span>
                      ))}
                    </div>
                    <h2 style={{
                      fontFamily: '"Playfair Display", Georgia, serif',
                      fontSize: 'clamp(1.8rem, 3vw, 2.6rem)',
                      fontWeight: 900, color: '#f5f0e8',
                      marginBottom: '10px', lineHeight: 1.1,
                    }}>{featured.name}</h2>
                    <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap', alignItems: 'center' }}>
                      {featured.language && <span style={{ fontSize: '13px', color: '#9ca3af' }}>🌐 {featured.language}</span>}
                      {featured.duration && <span style={{ fontSize: '13px', color: '#9ca3af' }}>⏱ {featured.duration}</span>}
                      {featured.categoryName && <span style={{ fontSize: '13px', color: '#9ca3af' }}>{featured.categoryName}</span>}
                      <span style={{ marginLeft: 'auto', fontSize: '14px', fontWeight: 700, color: '#e05c2a', display: 'flex', alignItems: 'center', gap: '4px' }}>
                        Book Now →
                      </span>
                    </div>
                  </div>
                </div>
              )}

              {/* ── Regular grid ── */}
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '16px' }}>
                {rest.map((event) => {
                  const color = TYPE_COLOR[event.type] || '#6b7280';
                  const icon  = TYPE_ICON[event.type]  || '🎪';
                  const isActive    = event.status === 'ACTIVE';
                  const isCancelled = event.status === 'CANCELLED';

                  return (
                    <div key={event.eventId} onClick={() => navigate(`/events/${event.eventId}`)}
                      style={{
                        background: 'rgba(255,255,255,0.03)',
                        border: '1px solid rgba(255,255,255,0.08)',
                        borderRadius: '16px', overflow: 'hidden',
                        cursor: 'pointer', transition: 'all 0.2s',
                        opacity: isCancelled ? 0.6 : 1,
                      }}
                      onMouseEnter={(e) => { e.currentTarget.style.transform = 'translateY(-4px)'; e.currentTarget.style.borderColor = `${color}50`; e.currentTarget.style.boxShadow = `0 12px 40px rgba(0,0,0,0.3)`; }}
                      onMouseLeave={(e) => { e.currentTarget.style.transform = 'none'; e.currentTarget.style.borderColor = 'rgba(255,255,255,0.08)'; e.currentTarget.style.boxShadow = 'none'; }}
                    >
                      {/* Color band */}
                      <div style={{ height: '3px', background: `linear-gradient(90deg, ${color}, transparent)` }} />

                      <div style={{ padding: '20px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '14px' }}>
                          <span style={{ fontSize: '11px', fontWeight: 700, color, background: `${color}18`, padding: '3px 9px', borderRadius: '99px' }}>
                            {icon} {event.type}
                          </span>
                          <span style={{
                            fontSize: '10px', fontWeight: 700, padding: '3px 8px', borderRadius: '99px',
                            background: isActive ? 'rgba(26,143,99,0.15)' : isCancelled ? 'rgba(232,48,90,0.15)' : 'rgba(107,114,128,0.15)',
                            color: isActive ? '#1a8f63' : isCancelled ? '#e8305a' : '#6b7280',
                          }}>
                            {event.status}
                          </span>
                        </div>

                        <h3 style={{
                          fontFamily: '"Playfair Display", Georgia, serif',
                          fontSize: '1.2rem', fontWeight: 700,
                          color: '#f5f0e8', marginBottom: '10px', lineHeight: 1.25,
                        }}>{event.name}</h3>

                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '5px', marginBottom: '14px' }}>
                          {event.genre && event.genre.split(',').slice(0,2).map((g) => (
                            <span key={g} style={{ fontSize: '10px', fontWeight: 600, color: '#6b7280', background: 'rgba(255,255,255,0.06)', padding: '2px 8px', borderRadius: '99px' }}>{g.trim()}</span>
                          ))}
                          {event.language && event.language.split(',').slice(0,1).map((l) => (
                            <span key={l} style={{ fontSize: '10px', fontWeight: 600, color: '#6b7280', background: 'rgba(255,255,255,0.06)', padding: '2px 8px', borderRadius: '99px' }}>🌐 {l.trim()}</span>
                          ))}
                          {event.duration && <span style={{ fontSize: '10px', fontWeight: 600, color: '#6b7280', background: 'rgba(255,255,255,0.06)', padding: '2px 8px', borderRadius: '99px' }}>⏱ {event.duration}</span>}
                        </div>

                        {event.summary && (
                          <p style={{ fontSize: '12px', color: '#4b5563', marginBottom: '14px', overflow: 'hidden', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', lineHeight: 1.5 }}>
                            📍 {event.summary}
                          </p>
                        )}

                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingTop: '12px', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
                          <span style={{ fontSize: '11px', color: '#4b5563' }}>{event.categoryName || ''}</span>
                          {isActive ? (
                            <span style={{ fontSize: '13px', fontWeight: 700, color: '#e05c2a' }}>Book →</span>
                          ) : (
                            <span style={{ fontSize: '11px', color: '#4b5563' }}>{event.status}</span>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>

      <style>{`
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.3} }
        @keyframes spin  { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        input::placeholder { color: #4b5563; }
        option { background: #1c1f2a; color: #e8e4de; }
      `}</style>
    </div>
  );
};

export default BrowsePage;
